1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PRICE = 60;
4	
5	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
17	
18	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
19	
20	const componentBlockBaseFor = (count: number, type: string): number =>
21	  count === BLOCK_SIZE
22	    ? BLOCK_PRICE
23	    : count * BASE_PREMIUM_BY_ITEM_TYPE[type];
24	
25	const countByType = (items: Item[]): Map<string, number> =>
26	  items.reduce((counts, item) => {
27	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
28	    return counts;
29	  }, new Map<string, number>());
30	
31	const componentsBaseFor = (items: Item[]): number => {
32	  const countsByType = countByType(items);
33	  return Array.from(countsByType).reduce(
34	    (total, [type, count]) => total + componentBlockBaseFor(count, type),
35	    0
36	  );
37	};
38	
39	const CURSE_SURCHARGE_RATE = 0.5;
40	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
41	const HIGH_ENCHANTMENT_THRESHOLD = 5;
42	
43	const surchargesFor = (item: Item, base: number): number => {
44	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
45	  const highEnchantment = item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
46	  return curse + highEnchantment;
47	};
48	
49	const nonComponentBaseFor = (items: Item[]): number =>
50	  items.reduce((sum, item) => {
51	    const base = BASE_PREMIUM_BY_ITEM_TYPE[item.type];
52	    return sum + base + surchargesFor(item, base);
53	  }, 0);
54	
55	const LOYALTY_DISCOUNT_RATE = 0.2;
56	const LOYALTY_THRESHOLD_YEARS = 2;
57	
58	export function quote(input: { yearsWithMHPCO: number; items: Item[] }): number {
59	  const components = input.items.filter(isComponent);
60	  const nonComponents = input.items.filter((item) => !isComponent(item));
61	  const policyBase = nonComponentBaseFor(nonComponents) + componentsBaseFor(components);
62	  const loyaltyDiscount =
63	    input.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
64	  return policyBase - loyaltyDiscount + PROCESSING_FEE;
65	}
